import React from 'react'
import { Typography, makeStyles, TextField, Button } from '@material-ui/core'
import emailjs from 'emailjs-com'
import { init } from 'emailjs-com';
init("user_PuIaGaCRy94irht2x2Wl9");

const useStyles = makeStyles({
    content: {
        marginTop: "100px",
        paddingBottom: "100%"
    },
    contact: {
        margin: "60px"
    },
});

const ContactUs = () => {
    const classes = useStyles();

    function sendEmail(e) {
        e.preventDefault();

        emailjs.sendForm('gmail', 'template_6p9ev9k', e.target, 'user_PuIaGaCRy94irht2x2Wl9')
            .then(result => {
                console.log(result.text);
            }).catch(error => {
                console.log(error.text);
            })


        e.target.reset()
    }

    return (
        <div className={classes.content}>
            <Typography className={classes.contact} variant='h2' align='center'>
                Contact Us
            </Typography>

            <form onSubmit={sendEmail}>
                <TextField
                    name="name"
                    fullWidth
                    id="outlined-basic"
                    label="Name"
                    variant="outlined"
                    required />
                <TextField
                    name="email"
                    autoComplete="email"
                    fullWidth
                    id="outlined-basic"
                    label="Email"
                    variant="outlined"
                    required />
                <TextField
                    name="subject"
                    fullWidth
                    id="outlined-basic"
                    label="Subject"
                    variant="outlined"
                    required />
                <TextField
                    name="message"
                    fullWidth
                    id="outlined-multiline-static"
                    label="Message"
                    multiline
                    rows={10}
                    variant="outlined"
                    required
                />
                <Button
                    type="submit"
                    fullWidth
                    variant="contained"
                    color="primary"
                >
                    Submit
                </Button>
            </form>


        </div>
    )
}

export default ContactUs
